const body = $input.first().json.body || $input.first().json;
const event = body.event || '';
const title = body.title || '(제목 없음)';
const assignee = body.assignee || '';
const newStatus = body.newStatus || '';
const createdBy = body.createdBy || '';
const taskId = body.taskId || '';
const priority = body.priority || 'p3';

// 상태 라벨
const statusLabels = {
  todo: '할일', in_progress: '진행', needs_check: '검토',
  done: '완료', resolved: '해결', waiting: '대기'
};
const statusLabel = statusLabels[newStatus] || newStatus;

// 우선순위 아이콘
const priIcons = { p1: '🔴', p2: '🟡', p3: '⚪', p4: '⚪' };
const priIcon = priIcons[priority] || '';

// 알림 대상 결정
let notifyTargets = [];
let messageText = '';

if (event === 'task_created') {
  // 새 업무 배정 → 담당자에게
  if (assignee && assignee !== createdBy) {
    notifyTargets.push(assignee);
    messageText = `📋 새 업무 배정\n${priIcon} ${title}\n\n배정자: ${createdBy}\n담당: ${assignee}`;
  }
} else if (event === 'task_status_changed') {
  if (newStatus === 'needs_check') {
    // 검토 요청 → 관리자(장지호)에게
    notifyTargets.push('장지호');
    messageText = `🔍 검토 요청\n${title}\n\n${assignee || '담당자'}님이 검토를 요청했습니다`;
  } else if (newStatus === 'done') {
    // 완료 → 요청자에게 (assignee에게도)
    if (assignee) notifyTargets.push(assignee);
    notifyTargets.push('장지호');
    messageText = `✅ 완료\n${title}`;
  } else if (newStatus === 'in_progress') {
    // 시작 → 요청자에게만 (묶음 알림용이지만 즉시는 안 보냄)
    // 대표에게는 묶음 다이제스트로
  } else if (newStatus === 'todo') {
    // 수정 필요 되돌림 → 담당자에게
    if (assignee) {
      notifyTargets.push(assignee);
      messageText = `🔄 수정 필요\n${title}\n\n검토 결과 수정이 필요합니다`;
    }
  }
}

// 중복 제거
notifyTargets = [...new Set(notifyTargets)];

if (notifyTargets.length === 0 || !messageText) {
  return [{ json: { shouldSend: false } }];
}

return [{ json: { shouldSend: true, targets: notifyTargets, text: messageText, event, taskId } }];

const item = $input.first().json;
const targets = item.targets || [];
const text = item.text || '';

// staff → chatId 매핑 (2026-04-17 갱신)
// 확보: 이진선·장지호·이재혁 / 미확보: 장준혁·장다경·조승해·서향자·이혜자
const chatIdMap = {
  '장지호': '7713811206',
  '이재혁': '8312726947',
  '원장님': '8606163783',
  '이진선': '8606163783',
  '조승해': 'SEUNGHAE_CHAT_ID',
  '장다경': 'DAGYEONG_CHAT_ID',
  '장준혁': 'JUNHYUK_CHAT_ID',
  '서향자': 'HYANGJA_CHAT_ID',
  '이혜자': 'HYEJA_CHAT_ID'
};

const results = [];
for (const name of targets) {
  const chatId = chatIdMap[name];
  if (chatId && !chatId.includes('_CHAT_ID')) {
    results.push({ json: { chatId, text } });
  }
}

return results.length > 0 ? results : [{ json: { chatId: '7713811206', text } }];
